callGraph.callee:
orig_user_fn
            .sig
            .inputs
            .iter()
            .map(|arg| {
                if let FnArg::Typed(PatType { pat, .. }) = arg
                    && let Pat::Ident(ident) = pat.as_ref()
                {
                    let ident_name = &ident.ident;
                    return quote! {
                        let #ident_name = #ident_name.clone();
                    };
                }
                quote! {}
            }).collect

inputs
        .iter()
        .map(|arg| {
            let FnArg::Typed(arg) = arg else {
                return Err(syn::Error::new_spanned(
                    arg,
                    "receiver is not allowed in captured function",
                ));
            };
            Ok(arg.pat.to_token_stream())
        }).try_collect

input
        .split('_')
        .map(|word| {
            let mut chars = word.chars();
            match chars.next() {
                None => String::new(),
                Some(first_char) => {
                    format!("{}{}", first_char.to_uppercase(), chars.as_str())
                }
            }
        }).collect
